mapper.update:
/* com.matjzing.FrontLoginMapper.updateDormancyMember */
UPDATE MEMBER SET
      UPDATER_SEQ = #{updaterSeq}
    , UPDATE_DT = NOW(3)
    , UPDATER_IP = #{updaterIp}
    , CI = #{memberSeq}
    , DI = #{memberSeq}
    , ID = #{memberSeq}
    , GENDER_CD = '-'
    , PASSWORD = #{password}
    , NAME = '-'
    , NICKNAME = '-'
    , MOBILE_PHONE_NO = '-'
    , EMAIL = '-'
    , MEMBER_STATUS_CD = 'DORMANCY'
    , MEMBER_STATUS_CHANGE_DT = #{memberStatusChangeDt}
    , BIRTHDAY = '-'
WHERE
    MEMBER_SEQ = #{memberSeq}

/* com.matjzing.FrontLoginMapper.updateLoginFailureCount */
UPDATE MEMBER SET
      UPDATER_SEQ = #{updaterSeq}
    , UPDATE_DT = NOW(3)
    , UPDATER_IP = #{updaterIp}
    , LOGIN_FAILURE_COUNT = #{loginFailureCount}
WHERE
    MEMBER_SEQ = #{memberSeq}

/* com.matjzing.FrontLoginMapper.updateMember */
UPDATE MEMBER SET
      UPDATER_SEQ = #{memberSeq}
    , UPDATE_DT = NOW(3)
    , UPDATER_IP = #{updaterIp}
    , LOGIN_FAILURE_COUNT = 0
    , RECENT_LOGIN_DT = NOW(3)

    , AUTO_LOGIN_YN = #{autoLoginYn}


    , APP_VERSION = #{deviceInfo.appVersion}
    , OS_SECTION_CD = #{deviceInfo.osCd}
    , OS_VERSION = #{deviceInfo.osVersion}
    , DEVICE_MODEL_NAME = #{deviceInfo.deviceModelName}
    , DEVICE_MARKETING_NO = #{deviceInfo.deviceMarketingNo}
    , APP_PUSH_VALUE = #{deviceInfo.appPushValue}

WHERE
MEMBER_SEQ = #{memberSeq}

/* com.matjzing.FrontMemberMapper.deleteSecessionMember */
UPDATE SECESSION_MEMBER SET
      CI = MEMBER_SEQ
    , DI = MEMBER_SEQ
    , ID = MEMBER_SEQ
WHERE MOBILE_PHONE_NO = #{encMobilePhoneNo}

